import os
from typing import Optional

class LLMClient:
    """Minimal multi-provider wrapper. Extend with retry / caching as needed."""

    def __init__(self, provider: str, model: str):
        self.provider = provider
        self.model = model
        self._client = self._build_client()

    def _build_client(self):
        if self.provider == "openai":
            from openai import OpenAI
            return OpenAI()  # reads OPENAI_API_KEY from env
        elif self.provider == "anthropic":
            import anthropic
            return anthropic.Anthropic()  # reads ANTHROPIC_API_KEY from env
        elif self.provider == "google":
            import google.generativeai as genai
            genai.configure(api_key=os.environ["GOOGLE_API_KEY"])
            return genai.GenerativeModel(self.model)
        else:
            raise ValueError(f"Unknown provider: {self.provider}")

    def chat(self, system: str, user: str, max_tokens: int = 512) -> str:
        if self.provider == "openai":
            resp = self._client.chat.completions.create(
                model=self.model,
                messages=[
                    {"role": "system", "content": system},
                    {"role": "user",   "content": user},
                ],
                max_tokens=max_tokens,
            )
            return resp.choices[0].message.content

        elif self.provider == "anthropic":
            resp = self._client.messages.create(
                model=self.model,
                system=system,
                messages=[{"role": "user", "content": user}],
                max_tokens=max_tokens,
            )
            return resp.content[0].text

        elif self.provider == "google":
            # Gemini does not separate system from user in the same way;
            # prepend system to the user turn.
            prompt = f"{system}\n\n{user}"
            resp = self._client.generate_content(prompt)
            return resp.text

        raise RuntimeError("Unreachable")


