import time
import random

def chat_with_retry(client: LLMClient, system: str, user: str,
                    max_retries: int = 5) -> str:
    delay = 1.0
    for attempt in range(max_retries):
        try:
            return client.chat(system, user)
        except Exception as exc:
            if attempt == max_retries - 1:
                raise
            # Check if it's a rate-limit or server error (5xx)
            code = getattr(exc, "status_code", None) or getattr(exc, "http_status", None)
            if code not in (429, 500, 502, 503, 529):
                raise
            jitter = random.uniform(0, delay * 0.25)
            time.sleep(delay + jitter)
            delay = min(delay * 2, 60)
    raise RuntimeError("Retry limit reached")
